INSERT INTO public.photos VALUES (25498, 'Puerta del Carmen c.1936', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. Aâ”œâ–’os 30. "Puerta del Carmen." Imagen de perfil, con visual de las apetitosas naves del Paseo de Pamplona.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65048400, -0.88771400, '0101000020E61000006971C6302768ECBF1F49490F43D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15160305586.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15160305586.webp', 'https://www.flickr.com/photos/zaragozaantigua/15160305586/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
