INSERT INTO public.photos VALUES (23135, 'Estaciâ”œâ”‚n Zaragoza Plaza 2006', 'Infografâ”œآ،a de la fachada exterior de la proyectada estaciâ”œâ”‚n del AVE Zaragoza Plaza, en las inmediaciones del nuevo barrio de Arcosur, la Feria de Muestras y la Plataforma Logâ”œآ،stica de Zaragoza (PLAZA). Esta segunda estaciâ”œâ”‚n del tren de Alta Velocidad en Zaragoza vio construida su primera fase entre 2006 y 2011, aâ”œâ–’o en que fue descartada, tanto en su faceta de apeadero del AVE como en la de cercanâ”œآ،as. En 2016 se iniciaba de nuevo el estudio de esta estaciâ”œâ”‚n. Fuente: Heraldo de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', NULL, 41.61722600, -0.96101100, '0101000020E6100000871403249AC0EEBFD61EF64201CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31804416931.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31804416931.webp', 'https://www.flickr.com/photos/zaragozaantigua/31804416931/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25502, 'Puerta del Carmen 1939', 'El 2 de mayo de 1939 se celebraron dos actos organizados por la Secciâ”œâ”‚n Juvenil de FET y de las JONS para conmemorar la universal fecha del 2 de mayo (de 1808). El primero, una misa de campaâ”œâ–’a ante la Puerta del Carmen, con presencia de las organizaciones juveniles del Râ”œآ®gimen franquista (Flechas, Pelayos, Cadetes), ademâ”œأ­s de autoridades militares y civiles, y pâ”œâ•‘blico. El segundo, una escenificaciâ”œâ”‚n dramatizada del relevo de la guardia ante la puerta, mientras un "Flecha" leâ”œآ،a elogios al 2 de mayo (de 1808). Luego leyâ”œâ”‚ discurso un concejal en nombre del Alcalde. Luego, el jefe provincial de la Falange, seâ”œâ–’or Muro. Luego, el jefe de la Quinta regiâ”œâ”‚n militar, general Raâ”œâ–’oy. Finalmente, desfilaron las organizaciones juveniles. Menudo fiestorro, en los dos sentidos. En la imagen, la Puerta del Carmen engalanada para la ocasiâ”œâ”‚n. A la izquierda, el antiguo convento de la Encarnaciâ”œâ”‚n de las Madres Carmelitas. Al fondo, la câ”œâ•‘pula de la parroquia de San Ildefonso, junto al Hospital Militar. Fuente visual: javierbarreiro.wordpress.com/category/sin-clasificar/', 1939, 1939, 1939, 'Anos 30', 'CENTRO', 41.64977300, -0.88758800, '0101000020E6100000384E0AF31E67ECBF7369FCC22BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15335301989.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15335301989.webp', 'https://www.flickr.com/photos/zaragozaantigua/15335301989/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25503, 'Puerta del Carmen 1940', '"Puerta del Carmen. Acto de propaganda en homenaje a los caâ”œآ،dos." Para llevar a cabo las celebraciones del 29 de octubre, dâ”œآ،a de los Caâ”œآ،dos (falangistas y, por extensiâ”œâ”‚n, nacionalistas), se escogiâ”œâ”‚ en 1938 la Puerta del Carmen como lugar emblemâ”œأ­tico y sâ”œآ،mbolo de la resistencia de la ciudad frente a los franceses. Para ello, se levantâ”œâ”‚ en el eje del vano central de la puerta una gran cruz, a los pies de la cual se depositaron un gran nâ”œâ•‘mero de coronas de flores rojas y amarillas, tras ella y sobre el vano central de la puerta, se leâ”œآ،a en grandes letras: "Presente". A ambos lados de la cruz, dos grandes pebeteros despedâ”œآ،an columnas de humo y sobre los portillos de los lados habâ”œآ،an sido colocadas coronas de laurel con lazos de los colores nacionalistas. Tambiâ”œآ®n se situaron a los lados cuatro falangistas con fusiles, y los abanderados de la Casa del Fascio (Italia) y de la Colonia Alemana, con sus respectivas banderas, todos ellos inmâ”œâ”‚viles junto a la cruz. Esto fue asâ”œآ، hasta que el "Altar de la Patria", luego redenominado "Monumento a los Hâ”œآ®roes y Mâ”œأ­rtires de Nuestra Gloriosa Cruzada", fue terminado en 1954... Mientras tanto, tanto italianos como alemanes, por circunstancias que no vienen al caso, desaparecieron de las celebraciones. Fuente visual: www1.dpz.es/cultura/agenda/2006/04/abril06-1.htm Fuente escrita: www.unizar.es/artigrama/pdf/24/3varia/13.pdf', 1940, 1940, 1940, 'Anos 40', 'CENTRO', 41.64979500, -0.88763400, '0101000020E61000004E2A1A6B7F67ECBF5A0D897B2CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15380451099.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15380451099.webp', 'https://www.flickr.com/photos/zaragozaantigua/15380451099/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
