INSERT INTO public.photos VALUES (25511, 'Puerta del Carmen 1934', 'Puerta del Carmen. A la izquierda, la iglesia y convento de las MM. Carmelitas de la Encarnaciâ”œâ”‚n. Al fondo, la calle de la Soberanâ”œآ،a Nacional. Fuente visual: Foto Conrado Barlâ”œآ®s, donada por Daniel Barlâ”œآ®s y digitalizada por Josâ”œآ® Luis Cintora para www.rafaelcastillejo.com', 1934, 1934, 1934, 'Anos 30', 'CENTRO', 41.64982500, -0.88759100, '0101000020E61000007C2AA73D2567ECBFC58F31772DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22615351584.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22615351584.webp', 'https://www.flickr.com/photos/zaragozaantigua/22615351584/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25512, 'Puerta del Carmen c.1942', 'Imagen de la Puerta del Carmen, aislada en una isleta con pequeâ”œâ–’a barandilla. Al fondo, los chaflaneros muros que delimitaban la iglesia y convento de las MM. Carmelitas de la Encarnaciâ”œâ”‚n. A su derecha, la antigua calle de la Soberanâ”œآ،a Nacional, entonces recientemente redenominada "General Sanjurjo". A su izquierda, el paseo de Marâ”œآ،a Agustâ”œآ،n. Los â”œأ­rboles de primer plano, del amplio andâ”œآ®n central peatonal del paseo de Pamplona. Fuente visual: Familia Cuyâ”œأ،s (cartotecadigital.icc.cat/)', 1942, 1942, 1942, 'Anos 40', 'CENTRO', 41.64982500, -0.88759100, '0101000020E61000007C2AA73D2567ECBFC58F31772DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24000143364.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24000143364.webp', 'https://www.flickr.com/photos/zaragozaantigua/24000143364/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25514, 'Puerta del Carmen c.1923', 'Vista de la Puerta del Carmen desde la calle de la Soberanâ”œآ،a Nacional. Tras ella, el paseo de Marâ”œآ،a Agustâ”œآ،n. Fuente: Foto Jesâ”œâ•‘s Cormâ”œأ­n. AMZ.', 1923, 1923, 1923, 'Anos 20', 'CENTRO', 41.64998600, -0.88746800, '0101000020E61000008FE3874A2366ECBFCE6DC2BD32D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24889006186.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24889006186.webp', 'https://www.flickr.com/photos/zaragozaantigua/24889006186/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25517, 'Puerta del Carmen c.1946', 'Vista de la puerta del Carmen desde afuera, con la calle del General Sanjurjo detrâ”œأ­s. A la izquierda, el convento de la Encarnaciâ”œâ”‚n. Fuente: www.facebook.com/photo.php?fbid=1516482491721047&set=...', 1946, 1946, 1946, 'Anos 40', 'CENTRO', 41.64987200, -0.88766000, '0101000020E61000009DF4BEF1B567ECBF064B75012FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27204752859.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27204752859.webp', 'https://www.flickr.com/photos/zaragozaantigua/27204752859/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25520, 'Puerta del Carmen aâ”œâ–’os 30', 'Vista de la Puerta del Carmen desde la confluencia del paseo Marâ”œآ،a Agustâ”œآ،n con la calle de Hernâ”œأ­n Cortâ”œآ®s, en un entorno en obras. Al fondo, la arbolada calle del General Sanjurjo. En la extrema derecha, el colegio de la Compaâ”œâ–’â”œآ،a de Marâ”œآ،a. Fuente visual: Heraldo.es', 1930, 1930, 1939, 'Anos 30', 'CENTRO', 41.64985300, -0.88777200, '0101000020E610000090BE49D3A068ECBF8F1A13622ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32950291361.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32950291361.webp', 'https://www.flickr.com/photos/zaragozaantigua/32950291361/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25523, 'Puerta del Carmen 1922', 'Dibujo de Dâ”œآ،az Domâ”œآ،nguez que muestra la Puerta del Carmen en 1922, con un carro atravesâ”œأ­ndola procedente de la ciudad. Fuente: Revista La Cadiera.', 1922, 1922, 1922, 'Anos 20', 'CENTRO', 41.64983200, -0.88770300, '0101000020E61000006FF4311F1068ECBF78F2E9B12DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/43142601042.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/43142601042.webp', 'https://www.flickr.com/photos/zaragozaantigua/43142601042/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25524, 'Zaragoza 1925', '"Anuncios econâ”œâ”‚micos. Cambio cuadro estilo futurista, por uno de Goya. Razâ”œâ”‚n, Ayuntamiento." Dibujo humorâ”œآ،stico de Luis Teixidor, "Teixi", en el diario "La voz de Aragâ”œâ”‚n". Hace referencia al urbanismo zaragozano de 1925, incluyendo alusiones al abastecimiento de aguas, a las expropiaciones, a la edificaciâ”œâ”‚n de la huerta de Santa Engracia, a la Casa de Socorro, al alumbrado supletorio, a la edificaciâ”œâ”‚n de las "Casas Baratas", al aislamiento de la Puerta del Carmen, a la nueva câ”œأ­rcel, al Mercado de Pescados, al puente del Gâ”œأ­llego, a los bancos anunciados, a la pavimentaciâ”œâ”‚n del paseo de la Independencia y al tranvâ”œآ،a a Casablanca. Cuestiones candentes en la â”œآ®poca, que quedan para siempre fijadas en un ingenioso collage.', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.64987200, -0.88763900, '0101000020E6100000BFEE74E78967ECBF064B75012FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50916237621.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50916237621.webp', 'https://www.flickr.com/photos/zaragozaantigua/50916237621/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25526, 'Puerta-del-Carmen c.1925', 'Inâ”œآ®dita imagen centrada en la Puerta del Carmen con una interesante vista tomada desde la glorieta entre el final del paseo de Pamplona y el principio del paseo de Marâ”œآ،a Agustâ”œآ،n. A la izquierda de la Puerta, tapias de la huerta del convento de la Encarnaciâ”œâ”‚n tras las que puede verse parcialmente la antigua iglesia y convento de ese nombre. Hacia el fondo, la arbolada calle de la Soberanâ”œآ،a Nacional. A la derecha, esquinero inmueble adosado a la Puerta y que albergaba el nâ”¬â•‘ 23 de esa calle (que albergaba la tienda de ultramarinos y comestibles de Agustâ”œآ،n Charles) y el nâ”¬â•‘ 4 del antiguo paseo de Ronda, en cuyos bajos destaca el toldo para atenuar la solanera del Cafâ”œآ® de Levante (asâ”œآ، llamado porque cuando se abriâ”œâ”‚ en 1895 aquâ”œآ، comenzaba la carretera de Valencia). Un ingreso a los lavaderos del Carmen se encontraba tras este inmueble, que poco despuâ”œآ®s fue expropiado por el Ayuntamiento para derribarlo y poder asâ”œآ، acometer el proyecto de aislamiento de la Puerta del Carmen.', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.64986700, -0.88766000, '0101000020E61000009DF4BEF1B567ECBFF4DF83D72ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53233164252.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53233164252.webp', 'https://www.flickr.com/photos/zaragozaantigua/53233164252/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26002, 'Vista aâ”œآ®rea Puerta del Carmen 1986', 'Foto: Josâ”œآ® Luis Pomarâ”œâ”‚n Vista aâ”œآ®rea del entorno de la Puerta del Carmen. Fuente: Colecciâ”œâ”‚n Rafael Margalâ”œآ®.', 1986, 1986, 1986, 'Anos 80', 'CENTRO', 41.64982500, -0.88759100, '0101000020E61000007C2AA73D2567ECBFC58F31772DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22128984860.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22128984860.webp', 'https://www.flickr.com/photos/zaragozaantigua/22128984860/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20919, 'Cruz del Coso 1766', 'Alzado de la Cruz del Coso, Cristâ”œâ”‚bal Estorguâ”œآ،a, Zaragoza, 1766. "Consta de una columna central con pedestal y zâ”œâ”‚calo, rematada con una cruz rodeada de 12 columnas que sostienen un segundo cuerpo de orden jâ”œâ”‚nico rematado con câ”œâ•‘pula y veleta; tanto el primer cuerpo como el segundo van rodeados de una verja". Versiâ”œâ”‚n de este monumento zaragozano erigido en la actual plaza de Espaâ”œâ–’a, en 1766. Antes y despuâ”œآ®s habâ”œآ،a tenido otras configuraciones, desde el siglo XV hasta 1808. Se trata de un humilladero cristiano que hace referencia a la leyenda de los Innumerables Mâ”œأ­rtires de Zaragoza. Fuente: Archivo General de Simancas, Ministerio de Cultura de Espaâ”œâ–’a.', 1766, 1766, 1766, 'Siglo XIX', 'CENTRO', 41.65238300, -0.88090200, '0101000020E610000049641F645930ECBFB2BB404981D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19790094814.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19790094814.webp', 'https://www.flickr.com/photos/zaragozaantigua/19790094814/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20929, '&quot;Casa de Pilatos&quot; 1500', '"Patio de la casa de Pilatos de Zaragoza". Dibujo de Valentâ”œآ،n Carderera y Solano, realizado en 1855, con la vista del patio interior de una desaparecida casona seâ”œâ–’orial sita en la esquina de la antigua plaza de San Gil con la calle del Horno del Hospitalico, cuando el acceso a esta iglesia parroquial se hacâ”œآ،a por esa plaza (en el siglo XVIII, a la iglesia de San Gil, como a otras, le cambiaron la orientaciâ”œâ”‚n de los pies y la cabecera). Las trazas estructurales y decorativas propias del tardo-gâ”œâ”‚tico podrâ”œآ،an aproximar su fâ”œأ­brica a finales del siglo XV. La singularidad de la denominaciâ”œâ”‚n ("Pilatos") serâ”œآ،a una peculiar conexiâ”œâ”‚n entre el supuesto prefecto de la provincia romana de Judea en el siglo I de la Era, y el fabuloso martiriologio cristiano del siglo IV en la cercana "Cruz del Coso". Cuando Carderera realizâ”œâ”‚ este dibujo, el palacio era propiedad de la marquesa de Vilueâ”œâ–’a de Carrillo, y se encontraba en la esquina entre la calle de la Lechuga, y la de la puerta Cinegia. Fuente visual: ceres.mcu.es/', 1500, 1500, 1500, 'Siglo XIX', 'CENTRO', 41.65280000, -0.88019400, '0101000020E61000006555849B8C2AECBF166A4DF38ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24700673350.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24700673350.webp', 'https://www.flickr.com/photos/zaragozaantigua/24700673350/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20957, 'Puerta Cinegia c.1800', '"Puerta Cineja", Antonio Callaved, 2011. Representaciâ”œâ”‚n idealizada de la Puerta Cinegia de Zaragoza, en la actual plaza de Espaâ”œâ–’a, a la entrada del Tubo. Fuente: pinturascallaved.wordpress.com/5-mi-pintura-en-la-filatelia/', 1800, 1800, 1800, 'Siglo XIX', 'CENTRO', 41.65233500, -0.88054000, '0101000020E6100000213CDA38622DECBFA18499B67FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15275553211.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15275553211.webp', 'https://www.flickr.com/photos/zaragozaantigua/15275553211/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20965, 'Cruz del Coso 1826', 'Aguafuerte diseâ”œâ–’ado por Antonio Vicente y grabado por Josâ”œآ® Gabriel Lafuente, Zaragoza, 1826. Versiâ”œâ”‚n de este monumento zaragozano proyectado pero no realizado como aquâ”œآ، aparece, sino una versiâ”œâ”‚n mucho mâ”œأ­s sencilla erigida hasta 1835, cuando fue derribado. Antes habâ”œآ،a tenido otras configuraciones, desde el siglo XV hasta 1808. Se trata de un humilladero cristiano que hace referencia a la leyenda de los Innumerables Mâ”œأ­rtires de Zaragoza. Fuente: â”œأ¼lbum grâ”œأ­fico de Zaragoza, 1985.', 1826, 1826, 1826, 'Siglo XIX', 'CENTRO', 41.65238300, -0.88090200, '0101000020E610000049641F645930ECBFB2BB404981D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18870969913.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18870969913.webp', 'https://www.flickr.com/photos/zaragozaantigua/18870969913/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21045, 'Plaza de la Constituciâ”œâ”‚n 1860', 'Dibujo de la plaza de la Constituciâ”œâ”‚n con el fondo del salâ”œâ”‚n de paseo de Santa Engracia. Centra la plaza la neptuniana Fuente de la Princesa. A la derecha, el original edificio de la Diputaciâ”œâ”‚n provincial coronado por una enseâ”œâ–’a nacional de tamaâ”œâ–’o imposible hasta hace no demasiado tiempo. Los peatones y algâ”œâ•‘n carruaje transitan por un entorno que lamentablemente nunca tuvo los gruesos â”œأ­rboles que aquâ”œآ، figuran.', 1860, 1860, 1860, 'Siglo XIX', 'CENTRO', 41.65216800, -0.88115900, '0101000020E61000001E6FF25B7432ECBFB6BFB33D7AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52299716137.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52299716137.webp', 'https://www.flickr.com/photos/zaragozaantigua/52299716137/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21117, 'Plaza de la Constituciâ”œâ”‚n c.1880', 'Espectacular imagen de la plaza de la Constituciâ”œâ”‚n, diâ”œأ­fana y aparentemente desierta por el dilatado tiempo de exposiciâ”œâ”‚n que requerâ”œآ،a consumar la captura fotogrâ”œأ­fica, de modo que apenas si aparecen localizados leves "rastros" o "sombras": una mâ”œآ،nima anâ”œآ®cdota. La foto, posiblemente, fue realizada desde altura en el palacio de la Diputaciâ”œâ”‚n Provincial. Domina el escenario de la plaza la provisoria fuente de Neptuno, que nos apunta directamente con su pâ”œآ®treo brazo. A la izquierda, edificios de la plaza, y del Coso, con el arranque de la calle de Don Jaime I. Entre esos edificios, inâ”œآ®dita imagen del antiguo nâ”¬â•‘ 47, casona que en sus bajos acogiâ”œâ”‚ la "Confiterâ”œآ،a del Arco de Cinegio", aquâ”œآ، "Pastelerâ”œآ،a de Bazâ”œأ­n". Unos aâ”œâ–’os mâ”œأ­s tarde serâ”œآ،a derribada la casa y, sobre ella se levantarâ”œآ،a un nuevo edificio ya de cuatro alturas, que no perdurarâ”œآ،a demasiado: en 1928, junto con su vecino de la derecha, formarâ”œأ­n el solar donde serâ”œأ­ construida una destacada central bancaria. Al fondo del Coso, soleado, el bloque del nâ”¬â•‘ 1 de la calle de Espartero. A la derecha, la que fuera antigua Fonda de Europa desde mediados de siglo, ya reformada y habilitada como "Gran Hotel de Europa", con el detalle de la peluquerâ”œآ،a que ocupaba su esquina. El suelo, parece todavâ”œآ،a sin el primer tendido tranviario de la ciudad, el que circulaba con propulsiâ”œâ”‚n de sangre. Fuente visual: Estudio Coyne, AHPZ-DARA', 1880, 1880, 1880, 'Siglo XIX', 'CENTRO', 41.65219700, -0.88107500, '0101000020E6100000A857CA32C431ECBF50C6F8307BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26407211070.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26407211070.webp', 'https://www.flickr.com/photos/zaragozaantigua/26407211070/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21152, 'Pl. de la Constituciâ”œâ”‚n 1894', 'Imagen de la. plaza de la Constituciâ”œâ”‚n con la fachada de los edificios del Coso. La francesa escultura del "dios" de los mares sigue soberana en este espacio. Al fondo, la calle Mâ”œأ­rtires. A su derecha, andamios de construcciâ”œâ”‚n del gran edificio del Coso, actuales nâ”œâ•‘meros 43-45, segâ”œâ•‘n proyecto de Antonio Miranda. A sus pies, un tranvâ”œآ،a a propulsiâ”œâ”‚n de sangre, posiblemente o de la lâ”œآ،nea del Arrabal, o de la del Bajo Aragâ”œâ”‚n. Justo a su derecha, solar en construcciâ”œâ”‚n de los edificios que en 1928 serâ”œأ­n derribados para levantar encima la nueva sede del Banco Zaragozano. Fuente visual: Archivo familiar Gâ”œâ”‚mez Laguna, en "El libro de oro de Aragâ”œâ”‚n", EPA, 1997.', 1894, 1894, 1894, 'Siglo XIX', 'CENTRO', 41.65234300, -0.88072900, '0101000020E6100000EB707495EE2EECBF2463B5F97FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18756989534.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18756989534.webp', 'https://www.flickr.com/photos/zaragozaantigua/18756989534/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21300, 'Pl. de la Constituciâ”œâ”‚n 1903', 'Fotografâ”œآ،a centrada en el "Antiguo Monumento a los Mâ”œأ­rtires" (sic) ubicado en la plaza de la Constituciâ”œâ”‚n, que es el moderno a los Mâ”œأ­rtires de la Religiâ”œâ”‚n y la Patria, sin el remate escultâ”œâ”‚rico escargado a Agustâ”œآ،n Querol y Subirats, culminado por un â”œأ­ngel victorioso, y sin la luminosa alegorâ”œآ،a femenina de Zaragoza. Con motivo de la visita a la ciudad del rey Alfonso XIII en octubre de ese aâ”œâ–’o, y para engalanar siquiera de forma efâ”œآ،mera lo que no era sino un â”œأ­rido pedestal coronado por la nada, cuya parte inferior parece un antecedente de la arquitectura brutalista, se colocâ”œâ”‚ la preciosa y monumental corona con lazo de la imagen, adornada con bombillas de colores. Una sublimaciâ”œâ”‚n de lo kitsch. Al fondo, antigua fachada edilicia del Coso, desde el nâ”¬â•‘ 29, antigua casa de Coloma, hasta el nâ”¬â•‘ 35. Transita un tranvâ”œآ،a "Primitivo" posiblemente en servicio en la lâ”œآ،nea 2. Madrid. Fuente visual: AMZ.', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.65223700, -0.88088000, '0101000020E6100000556AF6402B30ECBFDE1E84807CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32656919998.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32656919998.webp', 'https://www.flickr.com/photos/zaragozaantigua/32656919998/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21392, 'Pl. de la Constituciâ”œâ”‚n 1918', '"Trazo del Coso conocido como Brasero de los pobres". Foto: Julio Requejo, 8 de abril de 1918. Confluencia del Coso con la plaza de la Constituciâ”œâ”‚n de Zaragoza. Al fondo, entrada a la calle de Don Jaime I. La orientaciâ”œâ”‚n de las fachadas de este lugar hacia el sur propicia que su exposiciâ”œâ”‚n al sol resulte mâ”œأ­s câ”œأ­lida que en otras localizaciones. Fuente: DARA/AHPZ.', 1918, 1918, 1918, 'Anos 10', 'CENTRO', 41.65220800, -0.88042900, '0101000020E610000045662E70792CECBF44183F8D7BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21173092991.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21173092991.webp', 'https://www.flickr.com/photos/zaragozaantigua/21173092991/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21397, 'Pl. de la Constituciâ”œâ”‚n 1913', 'Luminosa imagen de la plaza de la Constituciâ”œâ”‚n capturada desde cerca del arranque de la calle de Don Jaime I, hacia donde se dirigen un par de carros tirados por caballerâ”œآ،as, en primer tâ”œآ®rmino, junto a un seâ”œâ–’or con una pata de palo. Tras ellos, un tranvâ”œآ،a "Jardinera-motora", posiblemente de la serie 25-28, en la terminal de la lâ”œآ،nea de Torrero y encaminado hacia el ascenso hasta la playa de Torrero. El fondo edilicio de la plaza aparece centrado por la decimonâ”œâ”‚nica fachada de la Diputaciâ”œâ”‚n Provincial, flanqueada por los inmuebles del nâ”¬â•‘ 1, a la derecha, y el nâ”¬â•‘ 3, a la izquierda, esquinero con el paseo de la Independencia, que poco despuâ”œآ®s serâ”œأ­ derribado y sustituido por uno nuevo como sede del Banco Hispano Americano. En los bajos de este edificio estaba desde 1858 el Cafâ”œآ® Suizo, desaparecido tras el derribo del inmueble.', 1913, 1913, 1913, 'Anos 10', 'CENTRO', 41.65219100, -0.88102000, '0101000020E6100000C5E6E3DA5031ECBF6EDFA3FE7AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21470799895.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21470799895.webp', 'https://www.flickr.com/photos/zaragozaantigua/21470799895/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23156, 'Calle Adolfo Suâ”œأ­rez 2007', 'Aspecto de la reciâ”œآ®n denominada calle de Adolfo Suâ”œأ­rez, en el barrio rural de la Venta del Olivar. Este camino rural sin asfaltar, antes sin nombre, serâ”œأ­ despuâ”œآ®s urbanizado. Al fondo, camino de Pinseque. Fuente: Heraldo de Aragâ”œâ”‚n.', 2007, 2007, 2007, 'Siglo XXI', NULL, 41.67706700, -0.96810700, '0101000020E6100000E2EA0088BBFAEEBFB519A721AAD64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32390264582.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32390264582.webp', 'https://www.flickr.com/photos/zaragozaantigua/32390264582/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21414, 'Pl. de la Constituciâ”œâ”‚n c.1912', 'Desde uno de los balcones del decimonâ”œâ”‚nico "Gran Hotel de Europa", una imagen desde cierta altura de la antigua plaza de la Constituciâ”œâ”‚n, y el emboque en ella del Coso alto. Al fondo, la que fuera "Casa de Juan Coloma" del XVI, luego palacio de los duques de Hâ”œآ،jar, ya habâ”œآ،a sido convertida en el elegante y modernista Casino Mercantil y Agrâ”œآ،cola, adaptado por Francisco Albiâ”œâ–’ana. A la izquierda, "La Joyita" (joyerâ”œآ،a) y la "Murga" (bombonerâ”œآ،a), ademâ”œأ­s de la cafeterâ”œآ،a "Gambrinus", en los bajos del edificio esquinero. A la derecha, otro seâ”œâ–’ero establecimiento: el "Gran Cafâ”œآ® Royalty", y el acceso a la calle de los Mâ”œأ­rtires. Los tranvâ”œآ،as traquetean como elâ”œآ®ctricos girâ”œâ”‚vagos para circunvalar la plaza, o bien para continuar por el Coso. Los toldos atenâ”œâ•‘an la severa solanera. Posiblemente, se trata de una postal editada y comercializada por la casa parisina "Levy Fils et Cie". Fuente: www.ebay.es/', 1912, 1912, 1912, 'Anos 10', 'CENTRO', 41.65243100, -0.88095600, '0101000020E610000015E126A3CA30ECBFC3F2E7DB82D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28482008524.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28482008524.webp', 'https://www.flickr.com/photos/zaragozaantigua/28482008524/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21423, 'MIguel Faci Abad 1912', 'Imagen de Miguel Faci Abad, joyero, fotâ”œâ”‚grafo aficionado, y amante de la fotografâ”œآ،a, autor de un prestigioso archivo (junto con su hermano Gabriel, que le da nombre) que contiene una mâ”œأ­s que interesante colecciâ”œâ”‚n de imâ”œأ­genes de la ciudad de los aâ”œâ–’os veinte y treinta del pasado siglo. La captura ha sido realizada en el "Art-Studio Gustavo Freudenthal", en su original ubicaciâ”œâ”‚n de la calle Coso nâ”¬â•‘ 31. Fuente visual: archivo fotogrâ”œأ­fico Gabriel Faci, AHPZ.', 1912, 1912, 1912, 'Anos 10', 'CENTRO', 41.65266700, -0.88108300, '0101000020E61000005DF8C1F9D431ECBFD7169E978AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31725996393.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31725996393.webp', 'https://www.flickr.com/photos/zaragozaantigua/31725996393/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21431, 'Pl. de la Constituciâ”œâ”‚n c.1918', 'Bulliciosa imagen de la plaza de la Constituciâ”œâ”‚n capturada posiblemente desde la altura del Hotel Europa, y centrada en la luminosa fachada del Coso recayente a la plaza. Al fondo, sobresale la torre de San Pablo Apâ”œâ”‚stol. Donde estuviera la antigua Casa de Coloma destaca el airoso remate en forma de palomar del reciente Centro Mercantil, Industrial y Agrâ”œآ،cola. Aunque el sol no es aâ”œâ•‘n el aplastante martillo canicular, muchos toldos del Coso estâ”œأ­n ya tendidos, como el del reciente Gran Cafâ”œآ® Royalty (nâ”¬â•‘ 35), y el del algo mâ”œأ­s veterano Gran Cafâ”œآ® Oriental (nâ”¬â•‘ 39), esquinero con la calle de los Mâ”œأ­rtires. A la izquierda del Royalty, sin toldos, la prestigiosa Joyerâ”œآ،a Agâ”œâ•‌eras (nâ”¬â•‘ 33). En primer plano, una unidad tranviaria de la serie Primitivos de la lâ”œآ،nea del Bajo Aragâ”œâ”‚n, y una composiciâ”œâ”‚n de jardineras (motor+dos remolques) de la lâ”œآ،nea que sube a la Playa de Torrero. Fuente visual: editorial Alberto Martâ”œآ،n (Barcelona)/colecciâ”œâ”‚n El Turismo Prâ”œأ­ctico, en Zaragoza estereoscâ”œâ”‚pica, fotografâ”œآ،a profesional y comercial 1850-1970, PUZ.', 1918, 1918, 1918, 'Anos 10', 'CENTRO', 41.65217000, -0.88071800, '0101000020E6100000F1F3DF83D72EECBF56B77A4E7AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34947191205.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34947191205.webp', 'https://www.flickr.com/photos/zaragozaantigua/34947191205/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21729, 'El Tâ”œآ،o Rana 1933', 'El Tâ”œآ،o Rana era un ansotano de gran envergadura que visitaba con frecuencia Zaragoza en los aâ”œâ–’os 20 y 30, vestido con el traje tâ”œآ،pico de su tierra. Tenâ”œآ،a mucho dinero procedente del ganado y la madera. Protagonizâ”œâ”‚ varias anâ”œآ®cdotas, relacionadas con el rechazo a su indumentaria. Al ser advertido en un hotel de lujo que â”œآ®ste estaba por encima de sus posibilidades, esgrimiâ”œâ”‚ un fajo de billetes y requiriâ”œâ”‚ comprar el edificio entero. Por la misma razâ”œâ”‚n, adquirâ”œآ،a dos localidades en el teatro Principal: una para â”œآ®l y otra para su sombrero. Se dice que en una ocasiâ”œâ”‚n, una compaâ”œâ–’â”œآ،a de zarzuela actuâ”œâ”‚ sâ”œâ”‚lo para â”œآ®l, al haber comprado todas las entradas. Tambiâ”œآ®n se cuenta que los potentados de la ciudad no pudieron utilizar los coches de caballos de alquiler a la salida de una corrida en la plaza de toros, puesto que â”œآ®l habâ”œآ،a pagado a todos para que circularan alrededor. Las incomprobables historias, que incluyen posibles descendientes no reconocidos y el uso de billetes para encenderse los puros por el paseo de la Independencia, son innumerables, como los mâ”œأ­rtires de Zaragoza. Lo vemos donde solâ”œآ،a sentarse: en el velador del cafâ”œآ® Royalty, en la plaza de la Constituciâ”œâ”‚n con acceso por la calle Mâ”œأ­rtires. El comercio de la derecha es la casa de vinos de Miguel Mur, con el portal del entonces nâ”œâ•‘mero 37 del Coso, anunciando al procurador Luis Villoro. Fuente visual: foto Gonzalo Reparaz Ruiz., en Institut Cartogrâ”œأ،fic i Geolâ”œâ–“gic de Catalunya.', 1933, 1933, 1933, 'Anos 30', 'CENTRO', 41.65232700, -0.88070900, '0101000020E6100000245F09A4C42EECBF1EA67D737FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21147570606.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21147570606.webp', 'https://www.flickr.com/photos/zaragozaan