INSERT INTO public.photos VALUES (21836, 'Jacques Doriot 1938', 'Imagen con motivo de la visita de Jacques Doriot, jefe del Partido Popular Francâ”œآ®s (PPF), sentado, en el centro, durante una veraniega gira de apoyo y respaldo por parte de este partido de la derecha extrema y fascista francesa, a la Espaâ”œâ–’a nacionalista en localidades como Irâ”œâ•‘n, San Sebastiâ”œأ­n, Bilbao, Santander, Burgos, Sevilla, Zaragoza... La captura se ha realizado posiblemente en la sede provincial de Falange Espaâ”œâ–’ola Tradicionalista, y detrâ”œأ­s de Doriot figura Jesâ”œâ•‘s Muro Sevilla, Jefe provincial de FET, ademâ”œأ­s de otros jerarcas locales. Junto a Doriot, Claude Popelin, miembro del Bureau Politique del PPF y su responsable de propaganda. Colaboracionista con la ocupaciâ”œâ”‚n alemana de Francia en 1940, en julio de 1941 Doriot impulsarâ”œأ­ activamente (junto con otros partidos de la derecha extrema francesa) la creaciâ”œâ”‚n de la Lâ”œآ®gion des volontaires franâ”œآ؛ais (contre le bolchâ”œآ®visme) o LVF, que participarâ”œأ­ en la agresiâ”œâ”‚n militar de la Alemania nazi contra la URSS. Fuente visual: revista "Vida Aragonesa, III Aâ”œâ–’o Triunfal".', 1938, 1938, 1938, 'Anos 30', 'CENTRO', 41.65253100, -0.88111500, '0101000020E6100000357BA0151832ECBF2750C42286D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34196737331.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34196737331.webp', 'https://www.flickr.com/photos/zaragozaantigua/34196737331/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21874, 'Pl. de la Constituciâ”œâ”‚n c.1935', 'Imagen centrada en el monumento a los dieciocho (recontados oficialmente como "innnumerables") mâ”œأ­rtires de Zaragoza sito en la plaza de la Constituciâ”œâ”‚n. Al fondo, principio del paseo de la Independencia. A la derecha, el edificio del antiguo banco Hispano Americano. Fuente visual: www.todocoleccion.net', 1935, 1935, 1935, 'Anos 30', 'CENTRO', 41.65218700, -0.88118000, '0101000020E6100000FB743C66A032ECBF2CF015DD7AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39946725911.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39946725911.webp', 'https://www.flickr.com/photos/zaragozaantigua/39946725911/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
